n = int(input())
s = input()
b = list(map(int, input().split()))


def get_max_beauty(s, b):
    n = len(s)
    beauty = 0
    for i in range(n // 2):
        if s[i] == s[n - i - 1]:
            beauty += max(b[i], b[n - i - 1])
        else:
            beauty += b[i] + b[n - i - 1]
    return beauty


print(get_max_beauty(s, b))
